import { dirname } from "node:path";
import postcss from "postcss";
import { generateTheme } from "./generate.js";
import { loadThemeFromFile } from "./theme-loader.js";

const AUTOGENERATED_COMMENT =
	"/** This file is autogenerated by the script. Do not edit it manually. */\n";

function parseThemePath(params) {
	const value = params.trim();

	if (
		(value.startsWith('"') && value.endsWith('"')) ||
		(value.startsWith("'") && value.endsWith("'"))
	) {
		return value.slice(1, -1);
	}

	throw new Error(
		'`@mantine-theme` expects a quoted file path, for example `@mantine-theme "./mantine-theme.ts";`',
	);
}

/**
 * @param {string} css
 * @param {{ from?: string, onDependency?: (file: string) => void }} [options]
 */
export async function expandMantineThemeDirectives(css, options = {}) {
	const { from, onDependency } = options;
	const root = postcss.parse(css, { from });
	const directives = [];

	root.walkAtRules("mantine-theme", (atRule) => {
		directives.push(atRule);
	});

	for (const atRule of directives) {
		const themePath = parseThemePath(atRule.params);
		const baseDir = from ? dirname(from) : process.cwd();
		const { absolutePath, theme } = await loadThemeFromFile(themePath, baseDir);
		const generatedCSS = generateTheme(theme).replace(
			AUTOGENERATED_COMMENT,
			"",
		);
		const generatedRoot = postcss.parse(generatedCSS, { from: absolutePath });

		onDependency?.(absolutePath);
		atRule.replaceWith(...generatedRoot.nodes);
	}

	return root.toString();
}
